/**
 * Material Symbols font set identifiers.
 *
 * These values correspond to the CSS class generated by the Google Fonts
 * stylesheet loaded in index.html. The active value must match the font
 * family loaded there.
 *
 * To use an icon style, the font family MUST be loaded in the index.html and the
 * fontSet property of the TbxMatFontIconService must match a corresponding loaded font.
 * The fontSet can be set application-wide via the TBX_MAT_FONT_ICON_DEFAULT_FONT_SET
 * token or per-instance via the TbxMatFontIconService constructor.
 *
 * See: https://fonts.google.com/icons
 */
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_ROUNDED = 'material-symbols-rounded';
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_OUTLINED = 'material-symbols-outlined';
export const TBX_MAT_ICON_FONT_SET_MATERIAL_SYMBOLS_SHARP = 'material-symbols-sharp';
